#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $q = new CGI;
my $log_dir = '/path/to/log/directory';
my $filename = $q->param('logfile') || 'default.log';

print $q->header(-type => 'text/html');

if (open(my $fh, '<', "$log_dir/$filename")) {
    while (my $line = <$fh>) {
        print $q->escapeHTML($line);
    }
    close($fh);
} else {
    print "Error opening log file: $!";
}